VALUES
  ('social-worker-moex-06960', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當檢定統計量的P值為小於預定的α值（α＝.05 2tail）時，下列關於此假設檢定的敘述，何者正確？', '["得以拒絕虛無假設", "可能犯了第二類型錯誤", "研究結論預定承擔至多5%的第一類型錯誤風險", "統計考驗力為95%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06961', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當社會工作研究者面臨接受服務的權利與評估服務效果義務的研究倫理兩難時，比較適切的作法是：', '["當遇到接受服務權利和評估服務效果義務的兩難時暫不處理", "考量服務使用者接受服務的權利，拒絕進行新處遇方案評估工作", "把接受新處遇案主的評估結果，和另組未接受新處遇案主的結果相比較", "把接受新處遇案主的評估結果，和在新處遇出現前使用一般處遇案主的評估結果相比較"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06962', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「效度（validity）」的敘述，何者正確﹖', '["研究者或其他專家對效度所作的客觀評估，稱為預測效度（predictive validity），它具有相當的說服力", "內容效度（content validity）指在某個概念下所包含的諸多意義，其測量工具所能夠加以涵蓋的程度", "研究法模擬考成績可以恰當反映日後社會工作師高等考試該科成績，表示其表面效度（face validity）好", "在李克特量表（Likert scale）中Cronbach’s α值高表示量表中的校標關聯效度（criterion-related validity）高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06963', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者最符合科學管理學派的論點？', '["重視人類的非理性層面對工作效率的影響", "強調組織生產流程中的變動性", "認為工作者的主要目的是經濟利益的取得", "主張組織的指揮權統一原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06964', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者最不符合全面品質管理的哲學理念？', '["品質是一個組織的主要目標", "消費者的滿意度是引導組織方向的刺激動力", "決策是以勇氣為基礎，做總比沒做好", "改變是持續性的，宜藉由團隊工作來完成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06965', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某社會服務組織的主任相當強調以個案為導向的福利服務，並力行組織精簡及簡化行政程序，建立客觀 績效評估標準的管理制度，請問該主任的管理哲學最符合下列何種管理理論學派的觀點？', '["行政管理學派", "科學管理學派", "人群關係學派", "新管理主義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06966', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '八○年代末期以來，資訊日新月異，顧客樣貌也日趨多元化，使得企業或服務組織必須適應不斷變化的 環境與顧客需求，於是學習型組織的管理思維遂成為組織獲取競爭優勢的關鍵之一，推展此管理思維的 最主要代表人物是：', '["彼得‧聖吉（Peter Senge）", "賈伯斯（Steve Jobs）", "戴明（William Deming）", "彼得‧杜拉克（Peter Drucker）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06967', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某社會服務機構正在執行當地社區老人送餐方案規劃之需求評估，該機構向目前有提供此項服務的組織 蒐集其服務狀況報告，以瞭解實際接受服務的老人人數，以及尚有多少潛在服務對象列入等待接受服務 的名單，此種需求評估方式稱為？', '["差補外推法需求評估", "相對性需求評估", "表達性需求評估", "感受性需求評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06968', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一般而言，在以成效為導向的服務方案規劃過程中，目標設定所強調的幾個構成要素，不包括：', '["達成目標的時間架構", "方案的預算系統", "方案結果測量的判準", "方案欲改變的標的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06969', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案的預算設計過程中，特別強調藉由利害關係競爭者之間協商過程的預算制定模式是：', '["政治模式的預算制定", "漸進增值模式的預算制定", "理性規劃模式的預算制定", "功能取向模式的預算制定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
